parameters.jsCode:
const intentData = $('Parse Intent Analysis').first().json;
const analysis = intentData.intent_analysis;
const rawResponse = $input.first().json;

const candidateText = rawResponse?.content?.[0]?.text || '';

const decisionMap = {
  'cta': { next_stage: 'cta', action: 'commit', cta_triggered: true },
  'qualify': { next_stage: 'qualification', action: 'none', cta_triggered: false },
  'clarify': { next_stage: 'clarification', action: 'none', cta_triggered: false },
  'escalate': { next_stage: 'escalated', action: 'none', cta_triggered: false }
};

const decision = decisionMap[analysis.cta_decision] || decisionMap['clarify'];

return [{ json: {
  status: candidateText ? 'success' : 'error',
  result: {
    candidate_response: candidateText,
    next_stage: decision.next_stage,
    action: decision.action,
    qualification_progress: analysis.qualification_progress || {},
    cta_triggered: decision.cta_triggered,
    escalate: analysis.escalate || false,
    escalation_reason: analysis.escalation_reason || '',
    detected_intent: analysis.detected_intent || 'unclear',
    language: analysis.language || 'english'
  },
  error: candidateText ? null : 'Claude returned empty response'
}}];
